  ('promotion-d592fc58-moex-00168', 'promotion-d592fc58', 'promotion-d592fc58-moex-112-3082b5f1', 'sub-promotion-d592fc58-04', NULL, 'single_choice', '依行政訴訟法規定，關於訴訟標的對於共同訴訟之各人，必須合一確定者，下列敘述何者錯誤？', '["他造對於共同訴訟人中之一人之行為，其效力及於全體", "共同訴訟人中之一人，生有訴訟當然停止之原因者，其效力及於全體", "共同訴訟人中之一人之行為有利益於共同訴訟人者，其效力及於全體", "共同訴訟人中之一人所為不利益於共同訴訟人之行為，其效力僅及於該人"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:38+00:00", "source_pdf_sha1": "b796954d584f", "answer_pdf_sha1": "403e55525a12", "source_family": "moex-gov-tw", "moex": {"exam_code": "112170", "c": "135", "s": "0408", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "行政法", "year": "112", "exam_name": "112年公務人員升官等考試、112年關務人員升官等考試、112年交通事業鐵路人員升資考試、112年交通事業港務人員升資考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "promotion", "civil_category": "商業行政"}'::jsonb, NULL),
